// Deterministic pseudo-random fan-out so venue pins spread realistically.
const jitter = (base: number, range: number, seed: number) => {
  const x = Math.sin(seed * 9999) * 10000;
  const n = x - Math.floor(x);
  return base + (n - 0.5) * range * 2;
};

const placeTemplate = (
  id: string, cityId: string, cityLat: number, cityLng: number,
  i: number, data: Partial<Place>
): Place => ({
  id,
  slug: data.slug ?? id,
  name: data.name ?? "Unnamed",
  cityId,
  neighborhood: data.neighborhood ?? "Downtown",
  address: data.address ?? "123 Main St",
  zip: data.zip ?? String(10000 + (i * 37) % 89999),
  lat: jitter(cityLat, 0.045, i),
  lng: jitter(cityLng, 0.045, i + 7),
  phone: data.phone,
  website: data.website,
  imageUrl: data.imageUrl ?? img("photo-1514933651103-005eec06c04b"),
  priceLevel: data.priceLevel ?? 2,
  rating: data.rating ?? 4.3,
  reviewCount: data.reviewCount ?? 400,
  vibeTags: data.vibeTags ?? ["after-work"],
  cuisineTags: data.cuisineTags ?? [],
  isFeatured: data.isFeatured ?? false,
  isClaimed: data.isClaimed ?? false,
  isVerified: data.isVerified ?? true,
  source: "manual",
  confidenceScore: 1.0
});

